from __future__ import annotations

import html
import os
from typing import Any

from fastapi import FastAPI, Form
from fastapi.responses import HTMLResponse, RedirectResponse

from rules import RuleError, validate_hours
from timestore import StoreError, TimeStore
from ui_kit import page


def create_web_app(store_path: str | os.PathLike[str] | None = None) -> FastAPI:
    """Build a FastAPI app bound to a single timesheet store file."""
    app = FastAPI()
    store = TimeStore(store_path)

    @app.get("/", response_class=HTMLResponse)
    def entries_page(week: str | None = None, project: str | None = None):
        try:
            entries = _filter_entries(store, week, project)
        except StoreError as exc:
            message = f"Invalid week '{week}': {exc}"
            return HTMLResponse(
                page("Timesheet", _render_error(message)), status_code=422
            )
        return page("Timesheet", _render_body(entries))

    @app.post("/entries")
    def add_entry(
        person: str = Form(...),
        project: str = Form(...),
        date: str = Form(...),
        hours: str = Form(...),
    ):
        try:
            hours_value = float(hours)
        except ValueError:
            message = f"Invalid hours '{hours}'"
            return HTMLResponse(
                page("Timesheet", _render_error(message)), status_code=422
            )

        day_total = sum(
            float(entry["hours"])
            for entry in store.list_entries()
            if entry["person"] == person and entry["date"] == date
        )

        try:
            validate_hours(hours_value, day_total)
        except RuleError as exc:
            message = f"Invalid hours: {exc}"
            return HTMLResponse(
                page("Timesheet", _render_error(message)), status_code=422
            )

        try:
            store.add_entry(person, project, date, hours_value)
        except StoreError as exc:
            message = f"Invalid date '{date}': {exc}"
            return HTMLResponse(
                page("Timesheet", _render_error(message)), status_code=422
            )

        return RedirectResponse(url="/", status_code=303)

    return app


def _filter_entries(
    store: TimeStore, week: str | None, project: str | None
) -> list[dict[str, Any]]:
    if week is not None:
        entries = store.entries_for_week(week)
        if project is not None:
            entries = [entry for entry in entries if entry["project"] == project]
        return entries
    if project is not None:
        return store.entries_for_project(project)
    return store.list_entries()


def _render_error(message: str) -> str:
    return f'<div class="ts-error">{html.escape(message)}</div>'


def _render_body(entries: list[dict[str, Any]]) -> str:
    if entries:
        rows = "".join(_render_row(entry) for entry in entries)
        listing = (
            '<table class="ts-table">'
            "<thead><tr>"
            "<th>Id</th><th>Person</th><th>Project</th><th>Date</th>"
            "<th>Hours</th><th>Status</th>"
            "</tr></thead>"
            f"<tbody>{rows}</tbody>"
            "</table>"
        )
    else:
        listing = '<p class="ts-empty">No entries yet.</p>'

    add_form = (
        '<form class="ts-form" data-testid="add-form" method="post" action="/entries">'
        '<input class="ts-input" type="text" name="person" placeholder="Person" required>'
        '<input class="ts-input" type="text" name="project" placeholder="Project" required>'
        '<input class="ts-input" type="date" name="date" required>'
        '<input class="ts-input" type="number" step="0.25" name="hours" placeholder="Hours" required>'
        '<button class="ts-button" type="submit">Add entry</button>'
        "</form>"
    )

    return (
        '<div class="ts-header"><h1>Timesheet</h1></div>'
        f"{listing}"
        f"{add_form}"
    )


def _render_row(entry: dict[str, Any]) -> str:
    entry_id = html.escape(str(entry["id"]))
    person = html.escape(str(entry["person"]))
    project = html.escape(str(entry["project"]))
    date = html.escape(str(entry["date"]))
    hours = html.escape(str(entry["hours"]))
    status = html.escape(str(entry["status"]))
    return (
        '<tr data-testid="entry-row">'
        f"<td>{entry_id}</td>"
        f"<td>{person}</td>"
        f"<td>{project}</td>"
        f"<td>{date}</td>"
        f"<td>{hours}</td>"
        f'<td><span class="ts-badge ts-badge--{status}">{status}</span></td>'
        "</tr>"
    )
